const staticData = $getWorkflowStaticData('global');
// W4: eigener Bucket pro run_id – Race-Condition-sicher bei parallelen Executions
staticData[run_id] = { results: [], run_date: new Date().toISOString() };

return [{ json: {
  run_id:          'update_' + new Date().toISOString().replace(/[^0-9]/g,'').slice(0,14),
  run_date:        new Date().toISOString(),
  // Striktes Verbot – diese Systeme werden NIEMALS angefasst
  exclude_ips:     ['10.1.1.100', '10.1.1.105', '10.1.1.180'],
  exclude_names:   ['n8n', 'claude'],
  // 'auto' = Reboot sofort | 'skip' = nur melden
  reboot_handling: 'auto',
  reboot_wait_sec: 90,
  proxmox_host:    '10.1.1.100',
} }];

const data         = $input.first().json;
const config       = $('📋 Set Config').first().json;
const systems      = data.systems || [];
const excl_ips    = config.exclude_ips   || [];
const excl_names  = config.exclude_names || [];

const active = systems.filter(s => {
  if (!s.ip) return false;
  const ip = (s.ip || '').split('/')[0].trim();
  if (excl_ips.includes(ip)) return false;
  if (excl_names.includes((s.name || '').toLowerCase())) return false;
  return true;
});

if (active.length === 0) {
  return [{ json: { _skip: true, name: '__no_systems__', ip: null, type: 'unknown',
    os_family: 'unknown', platform: null, run_id: config.run_id } }];
}
return active.map(s => ({ json: { ...s, run_id: config.run_id } }));

const sys        = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const run_id     = $('📋 Set Config').first().json.run_id;

// W2: Phantom-Eintrag __no_systems__ nicht in Report aufnehmen
if (sys.name === '__no_systems__') {
  return [{ json: { _skip: true, _phantom: true, system_name: '__no_systems__' } }];
}

const r = {
  run_id,
  system_name:      sys.name || sys.system_name || '?',
  system_ip:        sys.ip   || sys.system_ip   || null,
  system_type:      sys.type || 'unknown',
  system_os_family: sys.os_family || 'unknown',
  success:          false,
  ssh_success:      false,
  packages_updated: 0,
  apps_updated:     [],
  reboot_required:  false,
  reboot_triggered: false,
  errors:           ['System uebersprungen (kein IP oder in Ausschlussliste)'],
  summary:          'Uebersprungen',
  ticket_created:   false,
  _skip:            true,
};
// W4: in run_id-Bucket schreiben
if (!staticData[run_id]) staticData[run_id] = { results: [], run_date: new Date().toISOString() };
staticData[run_id].results.push(r);
return [{ json: r }];

const sys    = $input.first().json;
const config = $('📋 Set Config').first().json;

const ssh_user  = sys.ssh_user     || 'root';
const ssh_pass  = sys.ssh_password || '';
const isLXC     = sys.type === 'lxc';
const isDevice  = sys.type === 'device';
const proxmox   = config.proxmox_host || '10.1.1.100';
const os_family = sys.os_family   || 'unknown';
const platform  = (sys.platform && sys.platform.name) ? sys.platform.name : os_family;

// SSH-Prefix aufbauen
let ssh;
if (isLXC) {
  ssh = `ssh -o StrictHostKeyChecking=no -o ConnectTimeout=15 root@${proxmox} pct exec ${sys.id} --`;
} else if (ssh_pass) {
  ssh = `sshpass -p '${ssh_pass}' ssh -o StrictHostKeyChecking=no -o ConnectTimeout=15 ${ssh_user}@${sys.ip}`;
} else {
  ssh = `ssh -o StrictHostKeyChecking=no -o ConnectTimeout=15 ${ssh_user}@${sys.ip}`;
}

// OS-spezifische Befehle
const cmds = {
  apt: [
    `${ssh} bash -c "DEBIAN_FRONTEND=noninteractive apt-get update -q 2>&1 | tail -5"`,
    `${ssh} bash -c "DEBIAN_FRONTEND=noninteractive apt-get -y upgrade --with-new-pkgs 2>&1 | tail -30"`,
    `${ssh} bash -c "apt-get -y autoremove && apt-get clean 2>&1 | tail -5"`,
    `${ssh} bash -c "[ -f /var/run/reboot-required ] && echo REBOOT_NEEDED || echo NO_REBOOT"`,
  ],
  apk: [
    `${ssh} apk update 2>&1 | tail -5`,
    `${ssh} apk upgrade 2>&1 | tail -20`,
    `# Alpine: Reboot noetig wenn laufender Kernel != installierter Kernel (relevant bei physischen Alpine-Hosts)`,
    `${ssh} ash -c "KRUN=$(uname -r | cut -d- -f1); KINST=$(find /boot -name 'vmlinuz*' 2>/dev/null | grep -oP '\\d+\.\\d+\.\\d+' | head -1); [ -n \"$KINST\" ] && [ \"$KRUN\" != \"$KINST\" ] && echo REBOOT_NEEDED || echo NO_REBOOT"`,
  ],
  dnf: [
    `${ssh} bash -c "dnf -y upgrade 2>&1 | tail -30"`,
    `${ssh} bash -c "dnf -y autoremove 2>&1 | tail -5"`,
    `${ssh} bash -c "needs-restarting -r 2>/dev/null; [ \$? -eq 1 ] && echo REBOOT_NEEDED || echo NO_REBOOT"`,
  ],
  pacman: [
    `${ssh} bash -c "pacman -Syu --noconfirm 2>&1 | tail -20"`,
    `${ssh} bash -c "[ -f /var/run/reboot-required ] && echo REBOOT_NEEDED || echo NO_REBOOT"`,
  ],
  zypper: [
    `${ssh} bash -c "zypper -n update 2>&1 | tail -20"`,
    `${ssh} bash -c "zypper -n patch 2>&1 | tail -10"`,
    `${ssh} bash -c "zypper ps -s 2>/dev/null | grep -q reboot && echo REBOOT_NEEDED || echo NO_REBOOT"`,
  ],
  routeros: [
    `${ssh} "/system package update check-for-updates"`,
    `${ssh} "/system package update install"`,
    `# HINWEIS: SSH-Verbindung trennt sich nach install – RouterOS rebootet (das ist KEIN Fehler!)`,
    `sleep 90 && ${ssh} "/system resource print" 2>&1 || echo "ROUTEROS_RECONNECT_FAILED"`,
    `${ssh} "/system routerboard print"`,
    `${ssh} "/system routerboard upgrade"`,
  ],
  opkg: [
    `${ssh} "opkg update 2>&1 | tail -5"`,
    `${ssh} "opkg list-upgradable 2>/dev/null | cut -f 1 -d ' ' | xargs -r opkg upgrade 2>&1 | tail -20"`,
  ],
  vyos: [
    `${ssh} bash -c "sudo apt-get update -q 2>&1 | tail -5"`,
    `${ssh} bash -c "sudo apt-get -y upgrade --with-new-pkgs 2>&1 | tail -20"`,
    `${ssh} bash -c "[ -f /var/run/reboot-required ] && echo REBOOT_NEEDED || echo NO_REBOOT"`,
  ],
};

let update_steps = '';
let reboot_hint  = 'Setze reboot_required=true wenn REBOOT_NEEDED erscheint, sonst false.';

if (os_family === 'routeros') {
  update_steps = `**Schritt 1 – Update verfügbar prüfen:**\n${cmds.routeros[0]}\n\n**Schritt 2 – Update installieren (falls verfügbar):**\n${cmds.routeros[1]}\nACHTUNG: SSH-Verbindung trennt sich danach – RouterOS rebootet automatisch (das ist KEIN Fehler!)\n\n**Schritt 3 – 90s warten, dann Reconnect-Test:**\n${cmds.routeros[3]}\n\n**Schritt 4 – Routerboard Firmware (nach Reconnect):**\n${cmds.routeros[4]}\nFalls verfügbar: ${cmds.routeros[5]}`;
  reboot_hint = 'RouterOS rebootet automatisch nach Package-Install (SSH trennt sich – KEIN Fehler). Setze reboot_required=false, reboot_triggered=true wenn packages_updated > 0. Bei ROUTEROS_RECONNECT_FAILED: reboot_triggered=true aber Reconnect fehlgeschlagen – in errors[] melden.';

} else if (os_family === 'bsd') {
  update_steps = `**BSD-System (OPNsense/pfSense) erkannt.**\nAutomatisches Update ist nicht sicher via CLI möglich.\n${ssh} bash -c "opnsense-version 2>/dev/null || uname -a"\nNur Version ermitteln – kein Update durchführen.`;
  reboot_hint = 'BSD: Setze packages_updated=0, reboot_required=false. Füge in errors[] "Manuelles Update über Web-UI erforderlich" ein.';

} else {
  const family = cmds[os_family] ? os_family : 'apt';
  const c = cmds[family];
  const detect = os_family === 'unknown'
    ? `**Schritt 0 – OS erkennen:**\n${ssh} bash -c "cat /etc/os-release 2>/dev/null | head -5 || uname -a"\nPasse die nachfolgenden Befehle an das erkannte OS an.\n\n`
    : `**Erkanntes OS:** ${platform} (Paketmanager: ${family})\n\n`;
  update_steps = detect + c.join('\n');
}

const prompt = `Du bist ein erfahrener Systemadministrator. Führe AUSSCHLIESSLICH das OS-Basis-Update durch (Phase A). Kein Reboot, kein App-Update.

=== SYSTEM ===
Name: ${sys.name}
IP: ${sys.ip}
Typ: ${sys.type.toUpperCase()} | Klasse: ${sys.device_class || 'virtual'}
OS: ${platform} | OS-Familie: ${os_family}

=== PHASE A: OS-Update ===

${update_steps}

=== HINWEISE ===
- ${reboot_hint}
- Führe KEINEN Reboot durch – nur prüfen und melden
- Führe KEINE App-Updates durch (docker, npm, snap etc.) – das folgt in Phase C

=== ANTWORTFORMAT (NUR JSON, kein Markdown) ===
{"ssh_success":true,"packages_updated":0,"reboot_required":false,"errors":[],"summary":"Kurzbeschreibung"}

WICHTIG: Antworte NUR mit dem JSON-Objekt. Bei SSH-Fehler: ssh_success=false, errors=["Fehlermeldung"]`;

return [{ json: {
  system_name:      sys.name,
  system_ip:        sys.ip,
  system_type:      sys.type,
  system_id:        sys.id,
  system_os_family: os_family,
  device_class:     sys.device_class || 'virtual',
  is_device:        isDevice,
  is_lxc:           isLXC,
  is_routeros:      os_family === 'routeros',
  ssh_prefix:       ssh,
  proxmox:          proxmox,
  prompt
} }];

const claude     = $input.first().json;
const d          = $('🔧 Build OS Update Prompt').first().json;
const config     = $('📋 Set Config').first().json;

let step_a = {
  ssh_success:      false,
  packages_updated: 0,
  reboot_required:  false,
  errors:           ['Keine Antwort von Claude'],
  summary:          'Parse-Fehler',
};

try {
  const text    = claude.response_text || '';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match   = cleaned.match(/\{[\s\S]*\}/);
  if (match) step_a = { ...step_a, ...JSON.parse(match[0]) };
} catch(e) {
  step_a.errors.push('JSON Parse-Fehler: ' + e.message);
}

// RouterOS startet intern nach Package-Install automatisch neu
if (d.is_routeros && step_a.packages_updated > 0) {
  step_a.reboot_required  = false;
  step_a.reboot_triggered = true;
}

const should_reboot = step_a.reboot_required === true
  && (config.reboot_handling || 'auto') === 'auto';

// Fix 6: SSH-Fehler → Phase C überspringen
const skip_phase_c = step_a.ssh_success === false;

return [{ json: {
  skip_phase_c,
  system_name:      d.system_name,
  system_ip:        d.system_ip,
  system_type:      d.system_type,
  system_id:        d.system_id,
  system_os_family: d.system_os_family,
  device_class:     d.device_class,
  is_device:        d.is_device,
  is_lxc:           d.is_lxc,
  is_routeros:      d.is_routeros,
  ssh_prefix:       d.ssh_prefix,
  proxmox:          d.proxmox,
  reboot_handling:  config.reboot_handling || 'auto',
  should_reboot,
  step_a,
} }];

const d      = $input.first().json;
const config = $('📋 Set Config').first().json;

const wait   = config.reboot_wait_sec || 90;
const prox   = d.proxmox || config.proxmox_host;

let reboot_cmd, verify_cmd;

if (d.is_lxc) {
  reboot_cmd = `ssh -o StrictHostKeyChecking=no root@${prox} "pct reboot ${d.system_id}"`;
  verify_cmd = `ssh -o StrictHostKeyChecking=no root@${prox} "pct status ${d.system_id}"`;
} else {
  const ssh = d.ssh_prefix;
  reboot_cmd = `${ssh} bash -c "shutdown -r now 'Update-Reboot' 2>&1 || true"`;
  // Für Verify: nur SSH-Verbindbarkeit testen (kein Befehl)
  const base = ssh.replace(/--$/, '').trim();
  verify_cmd = `${base} -o ConnectTimeout=10 true 2>&1 && echo SSH_OK || echo SSH_TIMEOUT`;
}

const prompt = `Du bist ein Systemadministrator. Führe den Reboot durch und stelle sicher, dass das System danach wieder erreichbar ist.

=== SYSTEM ===
Name: ${d.system_name}
IP: ${d.system_ip}
Typ: ${d.system_type.toUpperCase()} (${d.is_lxc ? 'LXC Container' : 'Physical/VM'})

=== PHASE B: Reboot ===

**Schritt 1 – Reboot auslösen:**
${reboot_cmd}

**Schritt 2 – ${wait} Sekunden warten:**
sleep ${wait}

**Schritt 3 – Erreichbarkeit prüfen (bis zu 3 Versuche, Pause je 30s):**
Versuch 1: ${verify_cmd}
Bei Timeout: sleep 30, dann Versuch 2; bei erneutem Timeout: sleep 30, Versuch 3.
Für LXC: warte bis 'pct status ${d.system_id || ''}' → 'running'.

=== ANTWORTFORMAT (NUR JSON) ===
{"reboot_triggered":true,"reboot_success":true,"wait_seconds":${wait},"errors":[],"summary":"Reboot OK, System nach Xs wieder erreichbar"}

WICHTIG: Antworte NUR mit dem JSON-Objekt.`;

return [{ json: {
  system_name:      d.system_name,
  system_ip:        d.system_ip,
  system_type:      d.system_type,
  system_id:        d.system_id,
  system_os_family: d.system_os_family,
  device_class:     d.device_class,
  is_device:        d.is_device,
  is_lxc:           d.is_lxc,
  is_routeros:      d.is_routeros,
  ssh_prefix:       d.ssh_prefix,
  proxmox:          d.proxmox,
  reboot_handling:  d.reboot_handling,
  skip_phase_c:     d.skip_phase_c || false,
  step_a:           d.step_a,
  prompt
} }];

const claude = $input.first().json;
const d      = $('🔧 Build Reboot Prompt').first().json;

let step_b = {
  reboot_triggered: false,
  reboot_success:   false,
  wait_seconds:     0,
  errors:           ['Keine Antwort von Claude'],
  summary:          'Parse-Fehler',
};

try {
  const text    = claude.response_text || '';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match   = cleaned.match(/\{[\s\S]*\}/);
  if (match) step_b = { ...step_b, ...JSON.parse(match[0]) };
} catch(e) {
  step_b.errors.push('JSON Parse-Fehler: ' + e.message);
}

return [{ json: {
  system_name:      d.system_name,
  system_ip:        d.system_ip,
  system_type:      d.system_type,
  system_id:        d.system_id,
  system_os_family: d.system_os_family,
  device_class:     d.device_class,
  is_device:        d.is_device,
  is_lxc:           d.is_lxc,
  is_routeros:      d.is_routeros,
  ssh_prefix:       d.ssh_prefix,
  proxmox:          d.proxmox,
  reboot_handling:  d.reboot_handling,
  skip_phase_c:     d.skip_phase_c || false,
  step_a:           d.step_a,
  step_b,
} }];

// Eingang: entweder Parse Reboot Result (hat step_b) ODER Reboot nötig? false-Branch (kein step_b)
const d      = $input.first().json;
const step_b = d.step_b || null;
const ssh    = d.ssh_prefix;
const os_fam = d.system_os_family || 'apt';

// Fix 6: SSH-Fehler in Phase A → Phase C überspringen
if (d.skip_phase_c === true || d.step_a?.ssh_success === false) {
  const prompt = `Antworte NUR mit exakt diesem JSON-Objekt:\n{"apps_discovered":[],"apps_updated":[],"docker_updated":false,"pip_updated":false,"npm_updated":false,"snap_updated":false,"errors":["Phase C uebersprungen - SSH-Fehler in Phase A"],"summary":"Phase C uebersprungen wegen SSH-Fehler"}`;
  return [{ json: { ...d, step_b, prompt } }];
}

// RouterOS und BSD: kein sinnvolles App-Update via CLI möglich
if (d.is_routeros || os_fam === 'bsd') {
  const prompt = `Antworte NUR mit exakt diesem JSON-Objekt ohne weiteren Text:\n{"apps_discovered":[],"apps_updated":[],"docker_updated":false,"pip_updated":false,"npm_updated":false,"snap_updated":false,"errors":[],"summary":"Kein App-Update fuer ${os_fam} erforderlich"}`;
  return [{ json: { ...d, step_b, prompt } }];
}

const phase_b_note = step_b
  ? `Phase B (Reboot) wurde durchgefuehrt - System ist wieder online.`
  : `Phase B wurde uebersprungen (kein Reboot erforderlich).`;

// OS-spezifische Discovery-Befehle: manuell installierte Pakete vs. OS-Basis
let disc_a = '', disc_b = '';

if (['apt', 'vyos', 'unknown'].includes(os_fam)) {
  disc_a = `${ssh} bash -c "apt-mark showmanual 2>/dev/null | sort"`;
  disc_b = `${ssh} bash -c "systemctl list-units --type=service --state=running --no-pager --no-legend 2>/dev/null | awk '{print \\$1}' | grep -vE '^(ssh|sshd|cron|atd|rsyslog|systemd-|dbus\\.service|network|udev|getty|console|keyboard|swap|tmp\\.mount|syslog|ntp|chrony|apparmor|snapd\\.seeded|polkit|accounts-daemon|colord|avahi|bluetooth|ModemManager|packagekit|dm-event|lvm2|multipathd|fstrim)'"`;
} else if (os_fam === 'apk') {
  disc_a = `${ssh} ash -c "apk info 2>/dev/null | sort"`;
  disc_b = `${ssh} ash -c "rc-status --nocolor 2>/dev/null | grep started | awk '{print \\$1}'"`;
} else if (os_fam === 'dnf') {
  disc_a = `${ssh} bash -c "dnf history userinstalled 2>/dev/null | tail -60"`;
  disc_b = `${ssh} bash -c "systemctl list-units --type=service --state=running --no-pager --no-legend 2>/dev/null | awk '{print \\$1}' | grep -vE '^(ssh|cron|rsyslog|systemd-|dbus|network|udev|getty|swap|syslog|firewalld|chronyd|auditd|tuned|polkit|accounts|irqbalance|kdump|postfix\\.service)'"`;
} else if (os_fam === 'pacman') {
  disc_a = `${ssh} bash -c "pacman -Qe 2>/dev/null | awk '{print \\$1}' | sort"`;
  disc_b = `${ssh} bash -c "systemctl list-units --type=service --state=running --no-pager --no-legend 2>/dev/null | awk '{print \\$1}' | grep -vE '^(ssh|cron|systemd-|dbus|network|udev|getty|syslog)'"`;
} else if (os_fam === 'zypper') {
  disc_a = `${ssh} bash -c "zypper se -i --type package 2>/dev/null | awk '/^i/{print \\$3}' | sort"`;
  disc_b = `${ssh} bash -c "systemctl list-units --type=service --state=running --no-pager --no-legend 2>/dev/null | awk '{print \\$1}' | grep -vE '^(ssh|cron|systemd-|dbus|network|udev|getty|syslog|firewalld|chronyd)'"`;
}

const prompt = `Du bist ein erfahrener Systemadministrator. Fuehre Phase C durch: gruendliche Applikations-Discovery, dann gezieltes Update.
Qualitaet ist wichtiger als Geschwindigkeit - untersuche sorgfaeltig, was auf dem System installiert ist.
Phase A (OS-Update) ist abgeschlossen. ${phase_b_note}

=== SYSTEM ===
Name: ${d.system_name} | IP: ${d.system_ip} | OS-Familie: ${os_fam}

=== PHASE C - Schritt 1: Applikations-Discovery ===

**Discovery A - Manuell installierte Pakete (Diff gegen OS-Basis):**
${disc_a}
Filtere aus dem Ergebnis alle reinen OS-Basispakete heraus:
Ignoriere: init, coreutils, libc*, bash, dash, grep, sed, awk, tar, gzip, bzip2, xz, file, findutils, util-linux, procps, systemd*, dbus, udev, apt*, dpkg*, debconf, debianutils, login, passwd, shadow*, adduser, sudo (wenn nur sudo selbst), sysvinit*, insserv, base-files, base-passwd, hostname, ifupdown, isc-dhcp-client, netbase, iproute2, iptables, nftables, iputils*, net-tools, curl, wget, ca-certificates, openssl, libssl*, gnupg, gpg, python3-minimal, perl-base, sensible-utils, mime-support, tzdata, locales, man-db, manpages, less, nano, vim-tiny, rsyslog, logrotate, cron, at, acl, acpid, lsb-release, os-release, keyboard-configuration, console-setup, zlib1g, libz*, libgcc*, libc6, libstdc++
Alles was NICHT in dieser Liste ist = potenzielle Applikation.

**Discovery B - Laufende Nicht-System-Services:**
${disc_b}

**Discovery C - Python Virtual Environments:**
${ssh} bash -c "find /opt /srv /home /var/www /app /root -name pyvenv.cfg -maxdepth 7 2>/dev/null | head -20"
Fuer jede gefundene venv: ermittle Hauptpaket via <venv>/bin/pip list 2>/dev/null | head -10

**Discovery D - Docker Container:**
${ssh} bash -c "docker ps --format '{{.Names}}|{{.Image}}|{{.Status}}' 2>/dev/null || echo 'docker nicht verfuegbar'"

**Discovery E - npm global:**
${ssh} bash -c "npm list -g --depth=0 2>/dev/null || echo 'npm nicht verfuegbar'"

**Discovery F - snap:**
${ssh} bash -c "snap list 2>/dev/null || echo 'snap nicht verfuegbar'"

**Discovery G - Git-basierte Deployments:**
${ssh} bash -c "find /opt /srv /var/www -name .git -maxdepth 5 -type d 2>/dev/null | sed 's/\\/.git//' | head -15"

=== PHASE C - Schritt 2: Analyse ===

Identifiziere aus den Discovery-Ergebnissen ALLE installierten Nicht-Standard-Applikationen.
Eine Applikation liegt vor wenn mindestens eines zutrifft:
- In Discovery A: Paket das NICHT in der OS-Basisliste steht UND einen laufenden Service hat (Discovery B)
- In Discovery C: Python venv gefunden
- In Discovery D: Docker Container aktiv
- In Discovery E/F: npm global oder snap installiert
- In Discovery G: Git-Deployment vorhanden

=== PHASE C - Schritt 3: Update (Reihenfolge einhalten) ===

**a) Paketbasierte Apps (gezieltes Package-Upgrade, kein erneutes dist-upgrade):**
   apt:    ${ssh} bash -c "DEBIAN_FRONTEND=noninteractive apt-get install --only-upgrade -y <paket1> <paket2> 2>&1 | tail -15"
   dnf:    ${ssh} bash -c "dnf update -y <paket1> <paket2> 2>&1 | tail -15"
   apk:    ${ssh} apk upgrade <paket1> <paket2> 2>&1 | tail -10
   pacman: ${ssh} bash -c "pacman -S --noconfirm <paket1> 2>&1 | tail -10"
   zypper: ${ssh} bash -c "zypper -n update <paket1> 2>&1 | tail -10"

**b) Docker Container (Image-Update + Restart + Status-Check):**
   ${ssh} bash -c "docker pull <image> 2>&1 | tail -5 && docker restart <container> && sleep 5 && docker inspect --format '{{.State.Status}}' <container>"

**c) Python venvs (NUR Hauptpaket, keine vollstaendige Dependency-Aktualisierung):**
   ${ssh} bash -c "<venv>/bin/pip install --upgrade <hauptpaket> 2>&1 | tail -8"
   Danach: ${ssh} systemctl restart <service> && sleep 3 && systemctl is-active <service>

**d) npm global:**
   ${ssh} bash -c "npm update -g <paket> 2>&1 | tail -5"

**e) snap:**
   ${ssh} bash -c "snap refresh <paket> 2>&1 | tail -5"

**f) Git-Deployments:**
   ${ssh} bash -c "cd <pfad> && git pull 2>&1 | tail -5"
   Danach passenden Service neu starten und Status pruefen.

**Nach JEDEM Update:**
${ssh} bash -c "systemctl is-active <service> 2>/dev/null && echo 'SERVICE OK' || echo 'WARNUNG: Service nicht aktiv'"

**f2) Binaries ohne Paketmanager:**
