const claude = $input.first().json;
const d      = $('🔧 Build App Update Prompt').first().json;

let step_c = {
  apps_discovered: [],
  apps_updated:    [],
  docker_updated:  false,
  pip_updated:     false,
  npm_updated:     false,
  snap_updated:    false,
  errors:          [],
  summary:         '',
};

try {
  const text    = claude.response_text || '';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match   = cleaned.match(/\{[\s\S]*\}/);
  if (match) step_c = { ...step_c, ...JSON.parse(match[0]) };
} catch(e) {
  step_c.errors.push('JSON Parse-Fehler Step C: ' + e.message);
}

const step_a = d.step_a || {};
const step_b = d.step_b || null;

const all_errors = [
  ...(step_a.errors || []),
  ...(step_b ? (step_b.errors || []) : []),
  ...(step_c.errors || []),
];

const success = step_a.ssh_success === true && all_errors.length === 0;

return [{ json: {
  system_name:      d.system_name,
  system_ip:        d.system_ip,
  system_type:      d.system_type,
  system_id:        d.system_id,
  system_os_family: d.system_os_family,
  device_class:     d.device_class,
  // Aggregate
  success,
  ssh_success:      step_a.ssh_success      || false,
  packages_updated: step_a.packages_updated  || 0,
  apps_discovered:  step_c.apps_discovered   || [],
  apps_updated:     step_c.apps_updated      || [],
  reboot_required:  step_a.reboot_required   || false,
  reboot_triggered: step_b ? (step_b.reboot_triggered || false) : (step_a.reboot_triggered || false),
  errors:           all_errors,
  summary:          [step_a.summary, step_b ? step_b.summary : null, step_c.summary].filter(Boolean).join(' | '),
  ticket_created:   false,
  // Detailschritte
  step_a,
  step_b,
  step_c,
} }];

// FIX: Systemdaten immer aus Final Merge lesen, unabhängig vom Eingangsknoten
const d      = $('🔧 Parse App Update + Final Merge').item.json;
const config = $('📋 Set Config').first().json;

const errors_text = (d.errors || []).map((e, i) => `${i+1}. ${e}`).join('
') || 'Keine Details';

const step_b_md = d.step_b
  ? `### Phase B – Reboot
- Durchgeführt: ${d.step_b.reboot_triggered ? 'Ja' : 'Nein'} | Erfolgreich: ${d.step_b.reboot_success ? 'Ja' : 'Nein'}
- ${d.step_b.summary || ''}
`
  : '';

const body = `## Update-Fehler: ${d.system_name}

**System:** ${d.system_name} (${d.system_ip || 'N/A'})
**Typ:** ${d.system_type} | **Klasse:** ${d.device_class || '?'} | **OS:** ${d.system_os_family}
**Run-ID:** ${config.run_id}
**Zeitpunkt:** ${new Date().toISOString().slice(0,19).replace('T',' ')} UTC

---

## Fehler

${errors_text}

---

## Update-Schritte

### Phase A – OS-Update
- SSH-Erfolg: ${(d.step_a || {}).ssh_success ? 'Ja' : 'Nein'} | Pakete: ${(d.step_a || {}).packages_updated || 0} | Reboot erforderlich: ${(d.step_a || {}).reboot_required ? 'Ja' : 'Nein'}
- ${(d.step_a || {}).summary || ''}

${step_b_md}### Phase C – App-Update
- Apps aktualisiert: ${((d.step_c || {}).apps_updated || []).join(', ') || 'keine'}
- ${(d.step_c || {}).summary || ''}

---
*Automatisch erstellt durch MASTER: Update Management*`;

return [{ json: {
  title:         `[Update-Fehler] ${d.system_name} (${d.system_ip || 'N/A'})`,
  body,
  system_result: d,
  queue:         'Raw',
  state:         'neu',
  priority:      '2 high',
} }];

// FIX: System-Ergebnis aus Build Failure Ticket holen, ticket_id aus Create Ticket
const ticket       = $input.first().json;
const build_data   = $('🎫 Build Failure Ticket').first().json;

return [{ json: {
  ...build_data.system_result,
  ticket_created: true,
  ticket_id:      ticket.ticket_id     || null,
  ticket_number:  ticket.ticket_number || null,
} }];

const d          = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const run_id     = $('📋 Set Config').first().json.run_id;
// W4: in run_id-Bucket schreiben
if (!staticData[run_id]) staticData[run_id] = { results: [], run_date: new Date().toISOString() };
staticData[run_id].results.push({ ...d, run_id });
return [{ json: d }];

// W5: run_id aus Loop-Input (Filter & Prepare hat run_id mitgeliefert – kein Cross-Branch-Zugriff nötig)
const run_id     = $input.first().json.run_id;
const staticData = $getWorkflowStaticData('global');
// W4: run_id-Bucket lesen und löschen (verhindert Datenvermischung paralleler Executions)
const bucket  = staticData[run_id] || { results: [], run_date: new Date().toISOString() };
const results = bucket.results;
delete staticData[run_id];

const total           = results.length;
const success         = results.filter(r => r.success).length;
const failed          = results.filter(r => !r.success && !r._skip).length;
const skipped         = results.filter(r => r._skip).length;
const reboot_done     = results.filter(r => r.reboot_triggered).length;
const reboot_pending  = results.filter(r => r.reboot_required && !r.reboot_triggered).length;
const tickets_created = results.filter(r => r.ticket_created).length;
const packages_total  = results.reduce((s, r) => s + (r.packages_updated || 0), 0);

const summary = {
  run_id, run_date: bucket.run_date,
  total, success, failed, skipped,
  reboot_done, reboot_pending, tickets_created, packages_total,
  completed_at: new Date().toISOString(),
};

let report_md = `# Update-Report ${run_id}\n\n`;
report_md += `| Gesamt | Erfolgreich | Fehler | Uebersprungen | Reboots | Pakete |\n`;
report_md += `|--------|------------|--------|-------------|---------|--------|\n`;
report_md += `| ${total} | ${success} | ${failed} | ${skipped} | ${reboot_done} | ${packages_total} |\n\n`;
report_md += `## Systeme\n\n`;

for (const r of results) {
  const icon = r._skip ? '⏭️' : (r.success ? '✅' : '❌');
  const os   = r.system_os_family || '?';
  report_md += `### ${icon} ${r.system_name} (${r.system_ip || 'N/A'}) – ${os}\n`;
  if (!r._skip) {
    report_md += `- **Phase A:** ${r.packages_updated || 0} Pakete`;
    if (r.reboot_triggered) report_md += ` | **Reboot:** ✅ durchgefuehrt`;
    else if (r.reboot_required) report_md += ` | **Reboot:** ⏳ ausstehend`;
    if (r.apps_discovered && r.apps_discovered.length > 0) report_md += ` | **Discovered:** ${r.apps_discovered.length}`;
    if (r.apps_updated && r.apps_updated.length > 0) report_md += ` | **Updated:** ${r.apps_updated.join(', ')}`;
    report_md += '\n';
  }
  if (!r.success && (r.errors || []).length > 0) {
    report_md += `- **Fehler:** ${r.errors.slice(0,3).join('; ')}\n`;
  }
  if (r.summary) report_md += `- ${r.summary}\n`;
  report_md += '\n';
}

return [{ json: { summary, results, report_md, report_data: JSON.stringify(results) } }];
